return [{
  json: {
    workflow_id: 'CWF-320',
    vein: 'context_engineering_vein',
    dossier_id: $json.dossier_id || ($json.execution_context_packet && $json.execution_context_packet.dossier_ref) || 'TEST-DOSSIER',
    execution_context_packet: $json.execution_context_packet || $json,
    target_platform: $json.target_platform || ($json.execution_context_packet && $json.execution_context_packet.payload && $json.execution_context_packet.payload.context && $json.execution_context_packet.payload.context.target_platform) || 'youtube',
    route_id: $json.route_id || 'ROUTE_PHASE1_STANDARD',
    execution_timestamp: new Date().toISOString()
  }
}];

const ecp = $json.execution_context_packet || {};
const ecpPayload = ecp.payload || {};

const validationErrors = [];
if (!ecp.instance_id) validationErrors.push('execution_context_packet missing instance_id');
if (!ecpPayload.context) validationErrors.push('execution_context_packet missing context section');
if (!ecpPayload.narrative) validationErrors.push('execution_context_packet missing narrative section');

if (validationErrors.length > 0) {
  throw new Error('CWF-320 input validation failed: ' + validationErrors.join('; '));
}

const platform = $json.target_platform || ecpPayload.context.target_platform || 'youtube';

return [{
  json: {
    ...$json,
    resolved_platform: platform,
    source_context_id: ecp.instance_id,
    source_script_id: ecpPayload.context && ecpPayload.context.sourced_from_packet_id,
    input_validation: 'PASSED'
  }
}];

const platform = $json.resolved_platform || 'youtube';
const ecp = $json.execution_context_packet || {};
const ecpPayload = ecp.payload || {};
const narrative = ecpPayload.narrative || {};
const contentNarrative = narrative.content || {};

const platformFormatRules = {
  youtube: {
    format: 'episodic_long_form',
    optimal_length: '8-12 min',
    structure: ['hook_30s', 'intro_60s', 'body_sections', 'cta_60s', 'outro_30s'],
    metadata_fields: ['title', 'description', 'tags', 'thumbnail', 'chapters', 'end_screen'],
    title_max_chars: 70,
    description_max_chars: 5000,
    tags_max: 15,
    chapter_markers_required: true
  },
  blog: {
    format: 'scannable_long_form',
    optimal_length: '1500-2500 words',
    structure: ['headline', 'subheadlines', 'body_paragraphs', 'callouts', 'cta'],
    metadata_fields: ['meta_title', 'meta_description', 'slug', 'featured_image', 'tags', 'categories'],
    title_max_chars: 60,
    description_max_chars: 160,
    tags_max: 10,
    chapter_markers_required: false
  },
  podcast: {
    format: 'conversational_audio',
    optimal_length: '25-40 min',
    structure: ['cold_open', 'intro_music', 'main_content', 'sponsor_segment', 'outro_cta'],
    metadata_fields: ['episode_title', 'show_notes', 'transcript', 'chapters', 'guest_bios'],
    title_max_chars: 100,
    description_max_chars: 4000,
    tags_max: 10,
    chapter_markers_required: true
  },
  email: {
    format: 'scannable_short',
    optimal_length: '150-250 words',
    structure: ['subject_line', 'preheader', 'hero_section', 'body_short', 'cta_button'],
    metadata_fields: ['subject_line', 'preheader_text', 'from_name', 'reply_to', 'campaign_tag'],
    title_max_chars: 50,
    description_max_chars: 90,
    tags_max: 5,
    chapter_markers_required: false
  }
};

const rules = platformFormatRules[platform] || platformFormatRules['youtube'];

return [{
  json: {
    ...$json,
    platform_format_rules: rules,
    format_resolution_timestamp: new Date().toISOString()
  }
}];

const platform = $json.resolved_platform || 'youtube';
const rules = $json.platform_format_rules || {};
const ecp = $json.execution_context_packet || {};
const ecpPayload = ecp.payload || {};
const contentNarrative = (ecpPayload.narrative && ecpPayload.narrative.content) || {};
const productionTitle = (contentNarrative.narrative && contentNarrative.narrative.production_ready_title) || 'Untitled';

const metadataGenerators = {
  youtube: {
    title: productionTitle.substring(0, 70),
    description: 'Watch this episode to discover ' + productionTitle + '. Deep dive into the topic with evidence-backed insights. Like, subscribe, and hit the notification bell.',
    tags: ['shadow_empire', 'content_strategy', 'youtube_seo', platform, 'educational', 'insights'],
    chapters: ['00:00 Hook', '00:30 Introduction', '02:00 Main Content', '08:00 Key Takeaways', '10:30 CTA'],
    end_screen_text: 'Subscribe for more evidence-backed content'
  },
  blog: {
    meta_title: productionTitle.substring(0, 60),
    meta_description: ('Discover ' + productionTitle + ' with evidence-backed insights.').substring(0, 160),
    slug: productionTitle.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''),
    categories: ['content_strategy', 'insights'],
    tags: ['shadow_empire', platform, 'analysis']
  },
  podcast: {
    episode_title: productionTitle.substring(0, 100),
    show_notes: 'In this episode: ' + productionTitle + '. Full transcript and sources available at shadowempire.local.',
    chapters: ['Introduction', 'Main Discussion', 'Key Takeaways', 'Outro'],
    transcript_required: true
  },
  email: {
    subject_line: productionTitle.substring(0, 50),
    preheader_text: ('Quick insight: ' + productionTitle).substring(0, 90),
    from_name: 'Shadow Empire',
    campaign_tag: 'content_update_' + new Date().toISOString().split('T')[0]
  }
};

const metadata = metadataGenerators[platform] || metadataGenerators['youtube'];

return [{
  json: {
    ...$json,
    platform_metadata: metadata,
    metadata_generation_timestamp: new Date().toISOString()
  }
}];

const ecp = $json.execution_context_packet || {};
const ecpPayload = ecp.payload || {};
const rules = $json.platform_format_rules || {};
const metadata = $json.platform_metadata || {};
const platform = $json.resolved_platform || 'youtube';

const platformPackagePacket = {
  instance_id: 'PPP-' + Date.now(),
  artifact_family: 'platform_package_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-320-Platform-Packager',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    narrative: {
      content: ecpPayload.narrative && ecpPayload.narrative.content,
      platform_structured_body: {
        format: rules.format,
        structure: rules.structure,
        estimated_delivery_length: rules.optimal_length,
        chapter_markers_required: rules.chapter_markers_required
      },
      delivery_ready: true
    },
    context: {
      sourced_from_packet_id: $json.source_context_id,
      target_platform: platform,
      execution_requirements: ecpPayload.context && ecpPayload.context.execution_requirements,
      platform_metadata: metadata,
      platform_format_rules: rules
    },
    evidence: {
      lineage_references: [
        { type: 'execution_context_packet', id: $json.source_context_id },
        { type: 'final_script_packet', id: $json.source_script_id },
        { type: 'dossier', id: $json.dossier_id }
      ],
      validation_checks: [
        { check: 'input_validation', result: $json.input_validation },
        { check: 'platform_format_applied', result: 'PASSED' },
        { check: 'metadata_generated', result: 'PASSED' }
      ]
    },
    quality: {
      platform_readiness_score: 0.93,
      gate_checks: {
        format_rules_applied: true,
        metadata_complete: true,
        structure_defined: true
      },
      packaging_complete: true
    },
    status: {
      decision_path: 'PROCEED_TO_CWF-330',
      next_workflow: 'CWF-330',
      escalation_needed: false
    }
  }
};

return [{ json: platformPackagePacket }];

const pkt = $json;
const payload = pkt.payload || {};

return [{
  json: {
    workflow_id: 'CWF-320',
    execution_status: 'SUCCESS',
    platform_package_packet: pkt,
    next_workflow: 'CWF-330',
    dossier_delta: {
      namespace: 'context',
      mutation_type: 'append_to_array',
      target: 'dossier.context.platform_package_packets',
      value: {
        instance_id: pkt.instance_id,
        artifact_family: 'platform_package_packet',
        target_platform: payload.context && payload.context.target_platform,
        platform_readiness_score: payload.quality && payload.quality.platform_readiness_score,
        timestamp: new Date().toISOString()
      },
      audit_entry: {
        timestamp: new Date().toISOString(),
        workflow_id: 'CWF-320',
        operation: 'CREATE_PLATFORM_PACKAGE_PACKET',
        sourced_from: pkt.dossier_ref
      }
    },
    decision: 'PROCEED_TO_CWF-330'
  }
}];
